import React, { useContext, useEffect } from 'react';
import { Link, useNavigate } from 'react-router-dom';
import { Dropdown, Container } from 'react-bootstrap'; 
// Importaciones de Contextos
import { AuthContext } from '../context/AuthContext';
import { CartContext } from '../context/CartContext';
import { SettingsContext } from '../context/SettingsContext'; 
// Componentes dependientes
import SearchBox from './SearchBox';
import HeaderSkeleton from './HeaderSkeleton'; 
import styles from './Header.module.css'; // Importamos estilos CSS Module

const Header = () => {
  const navigate = useNavigate();
  // Renombramos loading para evitar conflictos
  const { userInfo: user, logout, loading: authLoading } = useContext(AuthContext); 
  const { cartItems, isItemJustAdded } = useContext(CartContext);
  const { settings, loading: settingsLoading } = useContext(SettingsContext);

  useEffect(() => {
    // Aplicar el color de acento de la configuración a las variables CSS globales
    if (settings?.accentColor) {
      document.documentElement.style.setProperty('--cta-color', settings.accentColor);
    }
  }, [settings]);

  const logoutHandler = () => {
    logout();
    navigate('/login');
  };

  // Cálculo de artículos totales para el badge del carrito
  const totalCartItems = cartItems.reduce((acc, item) => acc + item.qty, 0); 
  // Verificar si el usuario tiene permiso para el panel de administración
  const canAccessAdminPanel = user?.permissions?.includes('access:admin_panel');

  const isLoading = authLoading || settingsLoading;

  if (isLoading) {
     return <HeaderSkeleton />;
  }
  
  // Clases base para enlaces de navegación
  // Usamos el color blanco para el texto y transición para el hover
  const baseLinkClasses = "text-white no-underline hover:opacity-80 transition-opacity";
  
  return (
    // CRÍTICO: Eliminamos el rounded-b-xl para dejarlo recto. Usamos el CSS Module para estilos base.
    <header 
      className={`w-full sticky top-0 z-50 transition-all duration-300 shadow-md ${styles.header}`}
      style={{ backgroundColor: 'var(--brand-dark)' }} 
    >
      {/* py-3 para dar espacio arriba y abajo */}
      <Container className="py-3"> 
        {/* CRÍTICO: d-flex para la alineación horizontal de Logo, Search y Acciones */}
        <div className="d-flex justify-content-between align-items-center"> 
          
          {/* 1. Logo / Nombre del Sitio (Izquierda) */}
          <Link 
            to="/" 
            // Establece un ancho fijo para el logo para que el buscador se centre mejor
            className={`${baseLinkClasses} flex flex-col items-start h-full w-48 flex-shrink-0`}
          > 
            {settings?.logoUrl ? (
              // Si tenemos URL de logo, la usamos.
              <img 
                src={settings.logoUrl} 
                alt={settings.siteName || 'Tecnotitlan'} 
                style={{ height: '35px', objectFit: 'contain' }} 
              />
            ) : (
              // Si no, usamos el texto estilizado.
              <div className="flex flex-col items-start">
                  <span 
                    className="text-white text-xl font-extrabold tracking-widest uppercase" 
                    style={{ lineHeight: 1 }}
                  >
                    {settings?.siteName || 'TECNOTITLÁN'}
                  </span>
                  <span 
                    className="text-gray-400 text-xs font-light tracking-wide mt-0.5" 
                    style={{ lineHeight: 1 }} 
                  >
                    Tecnología con Raíces
                  </span>
              </div>
            )}
          </Link>

          {/* 2. Barra de búsqueda (Centrada, solo Desktop) */}
          {/* w-1/2 max-w-sm para el ancho del buscador, mx-auto para centrar */}
          <div className="d-none d-lg-block w-1/2 max-w-sm mx-auto">
            {/* SearchBox debe existir en components/ */}
            <SearchBox /> 
          </div>

          {/* 3. Navegación Derecha (Carrito y Usuario - Se mantiene a la derecha) */}
          {/* gap-6 para un buen espaciado entre elementos */}
          <nav className="d-flex align-items-center gap-6 w-auto flex-shrink-0">
            {/* Icono del Carrito */}
            <Link 
              to="/cart" 
              className={`relative ${baseLinkClasses} ${isItemJustAdded ? 'animate-pulse' : ''} flex items-center gap-2`}
              // CRÍTICO: Aplicamos el color de acento solo al ícono del carrito para resaltarlo
              style={{ color: 'var(--cta-color)' }} 
            >
              <i className="fas fa-shopping-cart text-xl"></i>
              <span className="d-none d-lg-inline text-white font-medium">Carrito</span>
              {totalCartItems > 0 && (
                // Badge rojo
                <span className="absolute -top-2 -right-4 bg-red-600 text-white text-[10px] font-bold px-1.5 py-0.5 rounded-full shadow-md z-10">
                  {totalCartItems}
                </span>
              )}
            </Link>

            {/* Menú de Usuario/Login */}
            {user ? (
              <Dropdown align="end" className="d-flex align-items-center">
                <Dropdown.Toggle 
                  as="a" 
                  className={`${baseLinkClasses} font-medium gap-2 cursor-pointer text-white no-underline flex items-center`} 
                  // Quitamos el borde por defecto del Dropdown
                  style={{ border: 'none', background: 'none' }}
                >
                  {/* Icono y texto de usuario */}
                  <div className="flex items-center gap-2">
                    <span className="d-none d-lg-inline">{user.name || 'Super Administrador'}</span>
                    <i className="fas fa-user-circle text-xl"></i> {/* Icono de persona */}
                  </div>
                </Dropdown.Toggle>

                <Dropdown.Menu className="shadow-xl border-0 rounded-lg mt-2 p-1 bg-white">
                  <Dropdown.Item as={Link} to="/profile" className="rounded py-2">Perfil</Dropdown.Item>
                  {canAccessAdminPanel && (
                    <Dropdown.Item as={Link} to="/admin/dashboard" className="rounded py-2">Panel Admin</Dropdown.Item>
                  )}
                  <Dropdown.Divider className="my-1" />
                  <Dropdown.Item onClick={logoutHandler} className="text-red-600 rounded py-2">Cerrar Sesión</Dropdown.Item>
                </Dropdown.Menu>
              </Dropdown>
            ) : (
              <Link to="/login" className={`${baseLinkClasses} font-medium gap-2 flex items-center`}>
                <i className="fas fa-user"></i> <span className="d-none d-lg-inline">Entrar</span>
              </Link>
            )}
          </nav>
        </div>
        
        {/* FILA 2: Barra de búsqueda (Solo Móvil - Se extiende en su propia fila) */}
        <div className="d-lg-none mt-3">
          <SearchBox />
        </div>
      </Container>
    </header>
  );
};

export default Header;
